input.command:
gh api graphql -F query='
query {
  repository(owner: "ronnnnn", name: "cc") {
    pullRequest(number: 81) {
      reviewThreads(first: 100) {
        nodes {
          id
          isResolved
          comments(first: 10) {
            nodes {
              databaseId
              body
              path
              line
              author { login }
            }
          }
        }
      }
    }
  }
}'
